		suggestionService.recordFeedback(request);
		return ResponseEntity.status(HttpStatus.CREATED).build();
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	/**
	 * Parses each {@link AiSuggestion}'s {@code suggestionPayload} JSON into an
	 * {@link InsightCardDto}. Rows whose payload cannot be parsed are silently
	 * skipped.
	 */
	private List<InsightCardDto> parseInsightCards(List<AiSuggestion> rows) {
		List<InsightCardDto> result = new ArrayList<>(rows.size());
		for (AiSuggestion row : rows) {
			try {
				JsonNode root = objectMapper.readTree(row.getSuggestionPayload());
				String insightText = root.path("insightText").asText(row.getRationale());
				String severity = root.path("severity").asText("LOW");
				String actionSuggestion = root.path("actionSuggestion").asText("");
				List<String> sourceEntityIds = new ArrayList<>();
				JsonNode idsNode = root.path("sourceEntityIds");
				if (idsNode.isArray()) {
					for (JsonNode n : idsNode) {
						sourceEntityIds.add(n.asText());
					}
				}
				String createdAt = row.getCreatedAt() != null ? row.getCreatedAt().toString() : "";
				result.add(new InsightCardDto(row.getId(), insightText, severity, sourceEntityIds, actionSuggestion,
						createdAt));
			} catch (Exception ex) {
				log.debug("Skipping unparseable insight payload for suggestion {}: {}", row.getId(), ex.getMessage());
			}
		}
		return result;
	}
}

package com.weeklycommit.ai.provider;

/**
 * Result returned by an {@link AiProvider}.
 *
 * <p>
 * When {@code available} is {@code false}, all other fields are meaningless and
 * callers should propagate {@code aiAvailable: false} to their response without
 * failing the request.
 */
public record AiSuggestionResult(
		/** {@code false} when the provider is down or AI is disabled. */
		boolean available,
		/**
		 * JSON-serialised suggestion payload. Structure varies by
		 * {@link AiContext#suggestionType()}.
		 */
		String payload,
		/** Human-readable rationale explaining why the suggestion was made. */
		String rationale,
		/**
		 * Provider confidence in the primary suggestion [0.0, 1.0]. Used for RCDO
		 * suggestions to filter below the surfacing threshold.
		 */
		double confidence,
		/** Provider model identifier for audit and reproducibility. */
		String modelVersion,
		/**
		 * Prompt template version identifier for A/B testing (e.g.
		 * "commit-draft-assist-v1"). May be null for older results.
		 */
		String promptVersion) {

	/**
	 * Backwards-compatible constructor for callers that do not yet provide a prompt
	 * version.
	 */
	public AiSuggestionResult(boolean available, String payload, String rationale, double confidence,
			String modelVersion) {
		this(available, payload, rationale, confidence, modelVersion, null);
	}

	/** Convenience factory for an unavailable (degraded) result. */
	public static AiSuggestionResult unavailable() {
		return new AiSuggestionResult(false, "{}", "AI provider unavailable", 0.0, "none", null);
	}
}

